sql:
SELECT user_id, username, email
FROM user_accounts
ORDER BY registration_date DESC;

SELECT username
FROM user_accounts
WHERE user_id IN (
  SELECT user_id
  FROM orders
);

SELECT DISTINCT user_id
FROM user_interactions
WHERE interaction_date BETWEEN 'yyyy-mm-dd' AND 'yyyy-mm-dd';

SELECT COUNT(DISTINCT o.order_id) AS total_orders
FROM orders o
INNER JOIN feedback f ON o.user_id = f.user_id AND o.restaurant_id = f.restaurant_id;

external_knowledge:
- "sailors" metaphorically refers to users;
- "sailed the ocean of excellence" metaphorically refers to giving a 5-star rating;
- "cost of their voyages" metaphorically refers to the total cost of orders placed by these users.

sql:
SELECT description, priority
FROM user_stories
WHERE ready_to_plan = 1;

external_knowledge:
- 'places' refers to 'restaurants';
- 'attracted the most attention lately' means 'have the highest number of interactions in the last week';
- 'how many times they've been interacted with over the past week' refers to the count of interactions during the last 7 days;
- The term 'top-performing' is implied by the highest interaction count.

- 'trailblazers' in this context refers to individual users exploring the restaurant scene;
- 'average journey through star ratings' is metaphorical for the average rating given by a user;
- 'cost landscapes they’ve navigated' refers to the average prices of dishes encountered by users in the restaurants they visit.

sql:
SELECT AVG(rating) AS average_rating
FROM restaurants
WHERE isDeliveryAvailable = 1;
